INSERT INTO `cases` VALUES (183,'CX-2026-0001',113,2,'X-Ray','ABDOMEN (PEDIA), ABDOMEN UPRIGHT','Routine','Without PhilHealth Card','','Pending','Approved','—',NULL,0,'2026-04-22 14:44:59',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL),(184,'CX-2026-0002',113,1,'X-Ray','FOOT','STAT','Without PhilHealth Card','','Completed','Approved','Uploaded','[\"public\\/assets\\/uploads\\/cases\\/case_184_1776941781_0.png\"]',1,'2026-04-23 10:46:41','','The bones of the foot demonstrate normal alignment and density. No evidence of fracture or dislocation is seen. Joint spaces are well maintained, and there is no significant soft tissue swelling or abnormal calcification.','No acute bony abnormality.','',5,7,'2026-04-23 22:17:57','FOOT','inactive','1970-01-01 00:00:00'),(185,'CX-2026-0003',114,1,'X-Ray','CHEST PA','STAT','Without PhilHealth Card','','Completed','Approved','Uploaded','[\"public\\/assets\\/uploads\\/cases\\/case_185_1776945278_0.png\"]',1,'2026-04-23 11:52:59','','The lung fields are clear without evidence of focal consolidation, mass, or infiltrates. The cardiac silhouette is within normal limits in size and configuration. The costophrenic angles are sharp and well-defined. No pleural effusion or pneumothorax is seen. The visualized osseous structures are intact.\n','No radiographic evidence of active cardiopulmonary disease.\n','',5,7,'2026-04-23 19:56:25','CHEST PA','inactive','1970-01-01 00:00:00'),(186,'CX-2026-0004',115,1,'X-Ray','CHEST PA, ELBOW','Routine','Without PhilHealth Card',NULL,'Completed','Approved','Uploaded','[\"public\\/assets\\/uploads\\/cases\\/case_186_1776945916_0.png\",\"public\\/assets\\/uploads\\/cases\\/case_186_1776945916_1.png\"]',1,'2026-04-23 12:02:07','','{\"CHEST PA\":{\"findings\":\"The lung fields are clear without evidence of focal consolidation, mass, or infiltrates. The cardiac silhouette is within normal limits in size and configuration. The costophrenic angles are sharp and well-defined. No pleural effusion or pneumothorax is seen. The visualized osseous structures are intact.\\n\",\"impression\":\"No radiographic evidence of active cardiopulmonary disease.\"},\"ELBOW\":{\"findings\":\"The bony structures of the elbow joint are intact with normal alignment. Joint spaces are preserved, and no evidence of fracture, dislocation, or joint effusion is noted. Surrounding soft tissues appear unremarkable.\",\"impression\":\"No acute osseous abnormality identified.\"}}','','',5,7,'2026-04-23 22:17:01','CHEST PA, ELBOW','inactive','1970-01-01 00:00:00'),(187,'CX-2026-0005',113,2,'X-Ray','ABDOMEN UPRIGHT','Urgent','Without PhilHealth Card','','Completed','Approved','Uploaded','[\"public\\/assets\\/uploads\\/cases\\/case_187_1776954181_0.png\"]',1,'2026-04-23 14:22:50','','The abdominal cavity shows a normal bowel gas pattern. No evidence of free air is seen beneath the diaphragm. There are no multiple air-fluid levels to suggest bowel obstruction. The visualized soft tissues and bony structures are unremarkable.\n','No radiographic evidence of pneumoperitoneum or bowel obstruction.\n','',5,10,'2026-04-23 22:23:37','ABDOMEN UPRIGHT','inactive','1970-01-01 00:00:00'),(188,'CX-2026-0006',116,1,'X-Ray','ABDOMEN (PEDIA), ABDOMEN UPRIGHT','STAT','Without PhilHealth Card','','Completed','Approved','Uploaded','[\"public\\/assets\\/uploads\\/cases\\/case_188_1776999735_0.png\",\"public\\/assets\\/uploads\\/cases\\/case_188_1776999735_1.png\"]',1,'2026-04-24 03:01:33','','{\"ABDOMEN (PEDIA)\":{\"findings\":\"There is a normal distribution of bowel gas within the abdomen. No dilated bowel loops or abnormal air-fluid levels are seen. No radiopaque foreign bodies or abnormal calcifications are identified. The soft tissue shadows are within normal limits, and the visualized bony structures appear intact.\\n\",\"impression\":\"No radiographic evidence of acute intra-abdominal pathology.\"},\"ABDOMEN UPRIGHT\":{\"findings\":\"The abdominal cavity shows a normal bowel gas pattern. No evidence of free air is 